sys_script_include.script:
function TableDelete(strTable)
{
	strTable = GetStringValue(strTable);

	if (IsValidTable(strTable,true) == false)
	{
		LogWarning('TableDelete: Table does not exist!');
		return false;
	}

	var bHasExtensions = RunScriptInGlobalScope(
		'var tableUtils = new TableUtils(param1); result = tableUtils.hasExtensions()',
		strTable);

    // Safety: do not accidentally delete an entire table hierarchy.
    if (bHasExtensions == true)
	{
		LogError('TableDelete: Table has extending tables.');
        return false;
    }

	RunScriptInGlobalScope('var tableUtils = new TableUtils();tableUtils.dropAndClean(param1);',strTable);

	if (IsValidTable(strTable,true) == true)
	{
		LogError('TableDelete: Failed to delete table "'+strTable+'"!');
		return false;
	}

	Log('TableDelete: table "'+strTable+'" has been deleted.');

	return true;

}
